import{_ as e,o as a,c as n,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"LinkedQL — The Database Primitive For Applications And Agents","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),s={name:"overview.md"};function r(o,t,l,d,h,p){return a(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="linkedql-—-the-database-primitive-for-applications-and-agents" tabindex="-1">LinkedQL <br>— The Database Primitive For Applications And Agents <a class="header-anchor" href="#linkedql-—-the-database-primitive-for-applications-and-agents" aria-label="Permalink to &quot;LinkedQL &lt;br&gt;— The Database Primitive For Applications And Agents&quot;">​</a></h1><p><strong>Welcome to the docs.</strong> This page gives you the core thinking around LinkedQL and helps you map the system at a glance.</p><hr><h2 id="what-is-linkedql" tabindex="-1">What is LinkedQL? <a class="header-anchor" href="#what-is-linkedql" aria-label="Permalink to &quot;What is LinkedQL?&quot;">​</a></h2><p>LinkedQL is an <strong>application-flavoured SQL</strong> that <strong>runs anywhere</strong>, with <strong>pluggable backends</strong>, and <strong>an offline- and sync-ready model</strong>.</p><p>That progression reflects how LinkedQL connects and composes modern application concerns.</p><hr><h2 id="how-that-expands" tabindex="-1">How That Expands <a class="header-anchor" href="#how-that-expands" aria-label="Permalink to &quot;How That Expands&quot;">​</a></h2><p>At the application-logic layer, LinkedQL gives you an upgrade path from SQL to <strong>a superset of SQL</strong> that:</p><ul><li>natively understands application-level paradigms – through a small set of additions to SQL (<a href="/lang">the LinkedQL language additions</a>)</li><li>can directly drive application state in real time – through database-native reactivity (<a href="/realtime">LinkedQL Realtime</a>)</li></ul><p>While its application-level surface is the invariant, LinkedQL can run wherever your app runs: on the <strong>client</strong>, the <strong>server</strong>, and the <strong>edge</strong>, as architecture demands.</p><p>Durable storage (<strong>PostgreSQL</strong>, <strong>MySQL/MariaDB</strong>, or <strong>client-side storage</strong>, depending on runtime environment) participates in the model as pluggable backends.</p><p>With modern applications spanning runtimes and crossing network boundaries, LinkedQL composes federation and sync into the storage layer as part of the model itself.</p><p>From the top-level SQL with capabilities to the pluggable storage layer with sync, LinkedQL forms a unified model that connects and composes modern application concerns.</p><p>That single model — replacing the traditional database stack of APIs, ORMs, realtime systems, and sync layers — is the design.</p><hr><h2 id="your-map-to-the-docs" tabindex="-1">Your Map to the Docs <a class="header-anchor" href="#your-map-to-the-docs" aria-label="Permalink to &quot;Your Map to the Docs&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Area</th><th style="text-align:left;">What it covers</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">Getting Started</td><td style="text-align:left;">Basic setup and first queries</td><td style="text-align:left;"><a href="/guides">LinkedQL Guides</a></td></tr><tr><td style="text-align:left;">API</td><td style="text-align:left;">Core execution model (query, stream, transactions, live queries)</td><td style="text-align:left;"><a href="/api">LinkedQL API</a></td></tr><tr><td style="text-align:left;">Language</td><td style="text-align:left;">SQL extensions and composable primitives</td><td style="text-align:left;"><a href="/lang">Language Additions</a></td></tr><tr><td style="text-align:left;">Realtime</td><td style="text-align:left;">Live queries and change propagation</td><td style="text-align:left;"><a href="/realtime">LinkedQL Realtime</a></td></tr><tr><td style="text-align:left;">FlashQL</td><td style="text-align:left;">Local execution, federation, and sync</td><td style="text-align:left;"><a href="/flashql">FlashQL</a></td></tr></tbody></table>',18)])])}const f=e(s,[["render",r]]);export{c as __pageData,f as default};
